ee:variables.ee:set-variable:
%dw 2.0
output application/java
---
{
	"sftp": {
		"fileName": message.attributes.name default "file-name-not-found",
		"inputPath": Mule::p('sftp.directory.customershipto.input'),
		"outputPath": Mule::p('sftp.directory.customershipto.output'),
		"failedPath": Mule::p('sftp.directory.customershipto.failed')
	},
	"email": {
		"subject" : "Customer Shit To SFTP to SF Sync Failed - " ++ message.attributes.name default "file-name-not-found"
	},
	"initialVars": {

		//email: vars.idocData.MATMAS05.API
		//email: Mule::p('outlook.recipients'),
		//docNum: vars.jsonData.FFCCUSN default "",
		//vtweg: vars.idocData.E1MARAM.E1MVKEM.VTWEG
	},
	"logger": {
		fileName: message.attributes.name default "file-name-not-found",
		//email: vars.idocData.E1KNA1M.Z1E1KNA1M.ZOWNER,
		//docNum: vars.idocData.EDI_DC40.DOCNUM
		email: Mule::p('outlook.recipients'),
		//docNum: vars.jsonData.FFCCUSN default "",
	}
}

json-logger:logger.json-logger:content:
#[output application/json ---
{
    payload: payload.^raw as String,
    attributes: attributes 
}]

ee:message.ee:set-payload:
%dw 2.0
output application/json
---
{
	apiName: Mule::p('api.name'),
	version: Mule::p('api.version'),
	timeStamp: now() as DateTime,
	success: false,
	errorDetails: [{
		message: payload.errors[0].message
	}]
}
